package users

type balanceAdjustment func(balance int64, amount int64) int64
type TransactionType = string

// Transaction types supported when adjusting user balances.
const (
	TransactionWin    TransactionType = "WIN"
	TransactionRefund TransactionType = "REFUND"
	TransactionSale   TransactionType = "SALE"
	TransactionBuy    TransactionType = "BUY"
	TransactionFee    TransactionType = "FEE"
)

var transactionBalanceAdjustments = map[TransactionType]balanceAdjustment{
	TransactionWin:    creditBalance,
	TransactionRefund: creditBalance,
	TransactionSale:   creditBalance,
	TransactionBuy:    debitBalance,
	TransactionFee:    debitBalance,
}

func creditBalance(balance int64, amount int64) int64 {
	return balance + amount
}

func debitBalance(balance int64, amount int64) int64 {
	return balance - amount
}

func applyTransactionBalance(balance int64, amount int64, transactionType string) (int64, error) {
	adjust, ok := transactionBalanceAdjustments[TransactionType(transactionType)]
	if !ok {
		return 0, ErrInvalidTransactionType
	}
	return adjust(balance, amount), nil
}

package users

import (
	"time"
)

const personalLinkFieldCount = 4

type personalLinksTarget interface {
	ApplyPersonalLinks(PersonalLinks)
}

// User represents the core user domain model
type User struct {
	ID                    int64
	Username              string
	DisplayName           string
	Email                 string
	UserType              string
	InitialAccountBalance int64
	AccountBalance        int64
	PersonalEmoji         string
	Description           string
	PersonalLink1         string
	PersonalLink2         string
	PersonalLink3         string
	PersonalLink4         string
	APIKey                string
	MustChangePassword    bool
	CreatedAt             time.Time
	UpdatedAt             time.Time
}

// ToPublicUser returns the public-safe projection of the user model.
func (u *User) ToPublicUser() *PublicUser {
	return new(PublicUser).FromUser(u)
}

// ToPrivateProfile returns the authenticated private projection of the user model.
func (u *User) ToPrivateProfile() *PrivateProfile {
	return new(PrivateProfile).FromUser(u)
}

func copyPublicUser(target *PublicUser, user *User) *PublicUser {
	if user == nil {
		return nil
	}

	if target == nil {
		target = &PublicUser{}
	}

	*target = PublicUser{
		ID:                    user.ID,
		Username:              user.Username,
		DisplayName:           user.DisplayName,
		UserType:              user.UserType,
		InitialAccountBalance: user.InitialAccountBalance,
		AccountBalance:        user.AccountBalance,
		PersonalEmoji:         user.PersonalEmoji,
		Description:           user.Description,
	}
	user.PersonalLinks().ApplyTo(target)
	return target
}

// FromUser copies the public-safe projection of the user model.
func (u *PublicUser) FromUser(user *User) *PublicUser {
	return copyPublicUser(u, user)
}

func copyPrivateProfile(target *PrivateProfile, user *User) *PrivateProfile {
	if user == nil {
		return nil
	}

	if target == nil {
		target = &PrivateProfile{}
	}

	*target = PrivateProfile{
		ID:                    user.ID,
		Username:              user.Username,
		DisplayName:           user.DisplayName,
		UserType:              user.UserType,
		InitialAccountBalance: user.InitialAccountBalance,
		AccountBalance:        user.AccountBalance,
		PersonalEmoji:         user.PersonalEmoji,
		Description:           user.Description,
		Email:                 user.Email,
		APIKey:                user.APIKey,
		MustChangePassword:    user.MustChangePassword,
		CreatedAt:             user.CreatedAt,
		UpdatedAt:             user.UpdatedAt,
	}
	user.PersonalLinks().ApplyTo(target)
	return target
}

// FromUser copies the authenticated private projection of the user model.
func (p *PrivateProfile) FromUser(user *User) *PrivateProfile {
	return copyPrivateProfile(p, user)
}

// ApplyUpdate mutates the user with the fields supported by UserUpdateRequest.
func (u *User) ApplyUpdate(req UserUpdateRequest) {
	if u == nil {
		return
	}

	u.DisplayName = req.DisplayName
	u.Description = req.Description
	u.PersonalEmoji = req.PersonalEmoji
	req.PersonalLinks().ApplyTo(u)
}

// PersonalLinks returns the personal-link fields currently stored on the user.
func (u *User) PersonalLinks() PersonalLinks {
	if u == nil {
		return PersonalLinks{}
	}

	return PersonalLinks{
		PersonalLink1: u.PersonalLink1,
		PersonalLink2: u.PersonalLink2,
		PersonalLink3: u.PersonalLink3,
		PersonalLink4: u.PersonalLink4,
	}
}

// PublicUser represents the public view of a user
type PublicUser struct {
	ID                    int64
	Username              string
	DisplayName           string
	UserType              string
	InitialAccountBalance int64
	AccountBalance        int64
	PersonalEmoji         string
	Description           string
	PersonalLink1         string
	PersonalLink2         string
	PersonalLink3         string
	PersonalLink4         string
}

// UserCreateRequest represents the data needed to create a new user
type UserCreateRequest struct {
	Username    string
	DisplayName string
	Email       string
	Password    string
	UserType    string
}

// NewUser builds the default domain user entity for the request.
func (r UserCreateRequest) NewUser() *User {
	return &User{
		Username:              r.Username,
		DisplayName:           r.DisplayName,
		Email:                 r.Email,
		UserType:              r.UserType,
		InitialAccountBalance: 0,
		AccountBalance:        0,
		MustChangePassword:    true,
	}
}

// UserUpdateRequest represents the data that can be updated for a user
type UserUpdateRequest struct {
	DisplayName   string
	Description   string
	PersonalEmoji string
	PersonalLink1 string
	PersonalLink2 string
	PersonalLink3 string
	PersonalLink4 string
}

// PersonalLinks returns the request's personal-link values in the domain storage shape.
func (r UserUpdateRequest) PersonalLinks() PersonalLinks {
	return PersonalLinks{
		PersonalLink1: r.PersonalLink1,
		PersonalLink2: r.PersonalLink2,
		PersonalLink3: r.PersonalLink3,
		PersonalLink4: r.PersonalLink4,
	}
}

// UserBet represents a bet placed by a user.
type UserBet struct {
	MarketID uint
	PlacedAt time.Time
}

// MarketUserPosition represents a user's position within a market.
type MarketUserPosition struct {
	YesSharesOwned int64
	NoSharesOwned  int64
}

// PortfolioItem captures aggregate information for a market within a user's portfolio.
type PortfolioItem struct {
	MarketID       uint
	QuestionTitle  string
	YesSharesOwned int64
	NoSharesOwned  int64
	LastBetPlaced  time.Time
}

// Portfolio represents the user's overall market positions.
type Portfolio struct {
	Items            []PortfolioItem
	TotalSharesOwned int64
}

// UserMarket represents a market a user has participated in.
type UserMarket struct {
	ID                      int64
	QuestionTitle           string
	Description             string
	OutcomeType             string
	ResolutionDateTime      time.Time
	FinalResolutionDateTime time.Time
	UTCOffset               int
	IsResolved              bool
	ResolutionResult        string
	InitialProbability      float64
	YesLabel                string
	NoLabel                 string
	CreatorUsername         string
	CreatedAt               time.Time
	UpdatedAt               time.Time
}

// PersonalLinks captures the set of personal links associated with a user profile.
type PersonalLinks struct {
	PersonalLink1 string
	PersonalLink2 string
	PersonalLink3 string
	PersonalLink4 string
}

// Values returns the links in storage order for bulk validation or sanitization.
func (p PersonalLinks) Values() []string {
	return []string{
		p.PersonalLink1,
		p.PersonalLink2,
		p.PersonalLink3,
		p.PersonalLink4,
	}
}

// NewPersonalLinks rebuilds personal links from an ordered value slice.
func NewPersonalLinks(values []string) PersonalLinks {
	if len(values) > personalLinkFieldCount {
		values = values[:personalLinkFieldCount]
	}

	links := PersonalLinks{}

// CreateUser creates a new user
func (s *Service) CreateUser(ctx context.Context, req UserCreateRequest) (*User, error) {
	if err := validateUsername(req.Username); err != nil {
		return nil, err
	}

	reader, err := s.userReader()
	if err != nil {
		return nil, err
	}
	if _, err := reader.GetByUsername(ctx, req.Username); err == nil {
		return nil, ErrUserAlreadyExists
	} else if !errors.Is(err, ErrUserNotFound) {
		return nil, err
	}

	user := req.NewUser()

	writer, err := s.userWriter()
	if err != nil {
		return nil, err
	}
	if err := writer.Create(ctx, user); err != nil {
		return nil, err
	}

	return user, nil
}

// UpdateUser updates user information
func (s *Service) UpdateUser(ctx context.Context, username string, req UserUpdateRequest) (*User, error) {
	return s.updateUserProfile(ctx, username, func(user *User) error {
		user.ApplyUpdate(req)
		return nil
	})
}

// ListUsers returns a list of users with filters
func (s *Service) ListUsers(ctx context.Context, filters ListFilters) ([]*User, error) {
	lister, err := s.userLister()
	if err != nil {
		return nil, err
	}
	users, err := lister.List(ctx, filters)
	if err != nil {
		return nil, err
	}
	if users == nil {
		return []*User{}, nil
	}
	return users, nil
}

// DeleteUser removes a user
func (s *Service) DeleteUser(ctx context.Context, username string) error {
	if err := s.ValidateUserExists(ctx, username); err != nil {
		return err
	}

	writer, err := s.userWriter()
	if err != nil {
		return err
	}
	return writer.Delete(ctx, username)
}

// ApplyTransaction adjusts the user's account balance based on the supplied transaction type.
func (s *Service) ApplyTransaction(ctx context.Context, username string, amount int64, transactionType string) error {
	return s.updateUserBalance(ctx, username, func(user *User) (int64, error) {
		return applyTransactionBalance(user.AccountBalance, amount, transactionType)
	})
}

// GetUserCredit returns the available credit for a user based on their balance and the maximum debt limit.
func (s *Service) GetUserCredit(ctx context.Context, username string, maximumDebtAllowed int64) (int64, error) {
	if err := validateUsername(username); err != nil {
		return 0, err
	}

	reader, err := s.userReader()
	if err != nil {
		return 0, err
	}
	user, err := reader.GetByUsername(ctx, username)
	if err != nil {
		if errors.Is(err, ErrUserNotFound) {
			return maximumDebtAllowed, nil
		}
		return 0, err
	}

	return maximumDebtAllowed + user.AccountBalance, nil
}

// GetUserPortfolio returns the user's portfolio across markets.
func (s *Service) GetUserPortfolio(ctx context.Context, username string) (*Portfolio, error) {
	if err := validateUsername(username); err != nil {
		return nil, err
	}

	portfolioRepo, err := s.userPortfolioRepository()
	if err != nil {
		return nil, err
	}
	bets, err := portfolioRepo.ListUserBets(ctx, username)
	if err != nil {
		return nil, err
	}

	marketMap := make(map[uint]*PortfolioItem)
	for _, bet := range bets {
		item, exists := marketMap[bet.MarketID]
		if !exists {
			item = &PortfolioItem{
				MarketID:      bet.MarketID,
				LastBetPlaced: bet.PlacedAt,
			}
			marketMap[bet.MarketID] = item
		}
		if bet.PlacedAt.After(item.LastBetPlaced) {
			item.LastBetPlaced = bet.PlacedAt
		}
	}

	var items []PortfolioItem
	var totalShares int64
	for marketID, item := range marketMap {
		position, err := portfolioRepo.GetUserPositionInMarket(ctx, int64(marketID), username)
		if err != nil {
			return nil, err
		}

		title, err := portfolioRepo.GetMarketQuestion(ctx, marketID)
		if err != nil {
			return nil, err
		}

		if position == nil {
			position = &MarketUserPosition{}
		}

		item.YesSharesOwned = position.YesSharesOwned
		item.NoSharesOwned = position.NoSharesOwned
		item.QuestionTitle = title
		totalShares += position.YesSharesOwned + position.NoSharesOwned

		items = append(items, *item)
	}

	sort.Slice(items, func(i, j int) bool {
		return items[i].LastBetPlaced.After(items[j].LastBetPlaced)
	})

	return &Portfolio{
		Items:            items,
		TotalSharesOwned: totalShares,
	}, nil
}

// ListUserMarkets returns markets the specified user has participated in.
func (s *Service) ListUserMarkets(ctx context.Context, userID int64) ([]*UserMarket, error) {
	if err := validateUserID(userID); err != nil {
		return nil, err
	}
	repo, err := s.userMarketsRepository()
	if err != nil {
		return nil, err
	}
	markets, err := repo.ListUserMarkets(ctx, userID)
	if err != nil {
		return nil, err
	}
	if markets == nil {
		return []*UserMarket{}, nil
	}
	return markets, nil
}

// GetUserFinancials returns the user's comprehensive financial snapshot.
func (s *Service) GetUserFinancials(ctx context.Context, username string) (map[string]int64, error) {
	if s.analytics == nil {
		return nil, ErrInvalidUserData
	}

	user, err := s.requireUser(ctx, username)
	if err != nil {
		return nil, err
	}

	snapshot, err := s.analytics.ComputeUserFinancials(ctx, analytics.FinancialSnapshotRequest{
		Username:       username,
		AccountBalance: user.AccountBalance,
	})
	if err != nil {
		return nil, err
	}
	if snapshot == nil {
		return map[string]int64{}, nil
	}

	return financialSnapshotToMap(snapshot), nil
}

// UpdateDescription sanitizes and updates a user's description.
func (s *Service) UpdateDescription(ctx context.Context, username, description string) (*User, error) {
	return s.updateProfileField(ctx, username, description, profileFieldSpecs["description"])
}

// UpdateDisplayName sanitizes and updates a user's display name.
func (s *Service) UpdateDisplayName(ctx context.Context, username, displayName string) (*User, error) {
	return s.updateProfileField(ctx, username, displayName, profileFieldSpecs["display_name"])
}

// UpdateEmoji sanitizes and updates a user's personal emoji.
func (s *Service) UpdateEmoji(ctx context.Context, username, emoji string) (*User, error) {
	return s.updateProfileField(ctx, username, emoji, profileFieldSpecs["emoji"])
}

// UpdatePersonalLinks sanitizes and updates a user's personal links.
func (s *Service) UpdatePersonalLinks(ctx context.Context, username string, links PersonalLinks) (*User, error) {
	sanitized, err := s.sanitizePersonalLinks(links)
	if err != nil {
		return nil, err
	}

	return s.updateUserProfile(ctx, username, func(user *User) error {
		sanitized.ApplyTo(user)
		return nil
	})
}

func (s *Service) sanitizePersonalLinks(links PersonalLinks) (PersonalLinks, error) {
	if err := s.requireSanitizer(); err != nil {
		return PersonalLinks{}, err
	}

	values := links.Values()
	for _, link := range values {
		if len(link) > 200 {
			return PersonalLinks{}, fmt.Errorf("personal link exceeds maximum length of 200 characters")
		}
	}

	sanitized := make([]string, len(values))
	for i, link := range values {
		if link == "" {
			sanitized[i] = ""
			continue
		}
		clean, err := s.sanitizer.SanitizePersonalLink(link)
		if err != nil {
			return PersonalLinks{}, fmt.Errorf("invalid personal link: %w", err)
		}
		sanitized[i] = clean
	}
	return NewPersonalLinks(sanitized), nil
}

