	user, err := s.requireUser(ctx, username)
	if err != nil {
		return err
	}

	newBalance, err := compute(user)
	if err != nil {
		return err
	}
	repo, err := s.userBalanceRepository()
	if err != nil {
		return err
	}
	return repo.UpdateBalance(ctx, username, newBalance)
